@@ -105,6 +105,10 @@ class FastMathFlags {
     return Flags != OtherFlags.Flags;
   }

+  bool operator==(const FastMathFlags &OtherFlags) const {
+    return Flags == OtherFlags.Flags;
+  }
+
   /// Print fast-math flags to \p O.
